mapper.select:
select e.*, c.category_name
from t_employee e
left join t_category c on e.dept_id = c.id


        and e.dept_id = #{categoryId}


        and e.work_id like concat('%',#{username},'%')


        and e.nickname like concat('%',#{nickname},'%')


        and e.status = #{status}


order by e.create_time desc
limit #{start},#{limit}

select count(id)
from t_employee


        and dept_id = #{categoryId}


        and work_id like concat('%',#{username},'%')


        and nickname like concat('%',#{nickname},'%')


        and status = #{status}
